arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
IDataView dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

var labelLookup = mlContext.Data.LoadFromEnumerable(new[]
{
    new LabelMapping { Churned = "Yes", Label = true },
    new LabelMapping { Churned = "No", Label = false },
});

var pipeline = mlContext.Transforms.Conversion.MapValue(
        "Label", labelLookup, labelLookup.Schema["Churned"], labelLookup.Schema["Label"],
        inputColumnName: nameof(CustomerData.Churned))
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.Age)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.Income)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age), nameof(CustomerData.Income), "RegionEncoded", nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

// With more data, use: var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
var model = pipeline.Fit(dataView);

var predictions = model.Transform(dataView);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);
Console.WriteLine($"Model saved to {modelPath}");

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST to /predict");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerData customer) =>
{
    var prediction = pool.Predict(customer);
    return Results.Ok(new
    {
        customer.Age,
        customer.Income,
        customer.Region,
        customer.PurchaseHistory,
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
    });
});

app.Run();

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = string.Empty;
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
}

public class LabelMapping
{
    public string Churned { get; set; } = string.Empty;
    public bool Label { get; set; }
}

